window.BIBLE["Ephesians"] = {"1":{"chapter":"1","title":"Ephesians 1","verses":{"1":{"text":"Paul, an apostle of Jesus Christ by the will of God, to the saints which are at Ephesus, and to the faithful in Christ Jesus:","ref":"Ephesians 1:1","synthesized":"Paul, an apostle of Jesus Christ by the will of God, to the saints which are at Ephesus, and to the faithful in Christ Jesus:","sources":{"KJV":{"text":"Paul, an apostle of Jesus Christ by the will of God, to the saints which are at Ephesus, and to the faithful in Christ Jesus:"}},"definableWords":[],"peopleInVerse":[]},"2":{"text":"Grace be to you, and peace, from God our Father, and from the Lord Jesus Christ.","ref":"Ephesians 1:2","synthesized":"Grace be to you, and peace, from God our Father, and from the Lord Jesus Christ.","sources":{"KJV":{"text":"Grace be to you, and peace, from God our Father, and from the Lord Jesus Christ."}},"definableWords":[],"peopleInVerse":[]},"3":{"text":"Blessed be the God and Father of our Lord Jesus Christ, who hath blessed us with all spiritual blessings in heavenly places in Christ:","ref":"Ephesians 1:3","synthesized":"Blessed be the God and Father of our Lord Jesus Christ, who hath blessed us with all spiritual blessings in heavenly places in Christ:","sources":{"KJV":{"text":"Blessed be the God and Father of our Lord Jesus Christ, who hath blessed us with all spiritual blessings in heavenly places in Christ:"}},"definableWords":[],"peopleInVerse":[]},"4":{"text":"According as he hath chosen us in him before the foundation of the world, that we should be holy and without blame before him in love:","ref":"Ephesians 1:4","synthesized":"According as he hath chosen us in him before the foundation of the world, that we should be holy and without blame before him in love:","sources":{"KJV":{"text":"According as he hath chosen us in him before the foundation of the world, that we should be holy and without blame before him in love:"}},"definableWords":[],"peopleInVerse":[]},"5":{"text":"Having predestinated us unto the adoption of children by Jesus Christ to himself, according to the good pleasure of his will,","ref":"Ephesians 1:5","synthesized":"Having predestinated us unto the adoption of children by Jesus Christ to himself, according to the good pleasure of his will,","sources":{"KJV":{"text":"Having predestinated us unto the adoption of children by Jesus Christ to himself, according to the good pleasure of his will,"}},"definableWords":[],"peopleInVerse":[]},"6":{"text":"To the praise of the glory of his grace, wherein he hath made us accepted in the beloved.","ref":"Ephesians 1:6","synthesized":"To the praise of the glory of his grace, wherein he hath made us accepted in the beloved.","sources":{"KJV":{"text":"To the praise of the glory of his grace, wherein he hath made us accepted in the beloved."}},"definableWords":[],"peopleInVerse":[]},"7":{"text":"In whom we have redemption through his blood, the forgiveness of sins, according to the riches of his grace;","ref":"Ephesians 1:7","synthesized":"In whom we have redemption through his blood, the forgiveness of sins, according to the riches of his grace;","sources":{"KJV":{"text":"In whom we have redemption through his blood, the forgiveness of sins, according to the riches of his grace;"}},"definableWords":[],"peopleInVerse":[]},"8":{"text":"Wherein he hath abounded toward us in all wisdom and prudence;","ref":"Ephesians 1:8","synthesized":"Wherein he hath abounded toward us in all wisdom and prudence;","sources":{"KJV":{"text":"Wherein he hath abounded toward us in all wisdom and prudence;"}},"definableWords":[],"peopleInVerse":[]},"9":{"text":"Having made known unto us the mystery of his will, according to his good pleasure which he hath purposed in himself:","ref":"Ephesians 1:9","synthesized":"Having made known unto us the mystery of his will, according to his good pleasure which he hath purposed in himself:","sources":{"KJV":{"text":"Having made known unto us the mystery of his will, according to his good pleasure which he hath purposed in himself:"}},"definableWords":[],"peopleInVerse":[]},"10":{"text":"That in the dispensation of the fulness of times he might gather together in one all things in Christ, both which are in heaven, and which are on earth; even in him:","ref":"Ephesians 1:10","synthesized":"That in the dispensation of the fulness of times he might gather together in one all things in Christ, both which are in heaven, and which are on earth; even in him:","sources":{"KJV":{"text":"That in the dispensation of the fulness of times he might gather together in one all things in Christ, both which are in heaven, and which are on earth; even in him:"}},"definableWords":[],"peopleInVerse":[]},"11":{"text":"In whom also we have obtained an inheritance, being predestinated according to the purpose of him who worketh all things after the counsel of his own will:","ref":"Ephesians 1:11","synthesized":"In whom also we have obtained an inheritance, being predestinated according to the purpose of him who worketh all things after the counsel of his own will:","sources":{"KJV":{"text":"In whom also we have obtained an inheritance, being predestinated according to the purpose of him who worketh all things after the counsel of his own will:"}},"definableWords":[],"peopleInVerse":[]},"12":{"text":"That we should be to the praise of his glory, who first trusted in Christ.","ref":"Ephesians 1:12","synthesized":"That we should be to the praise of his glory, who first trusted in Christ.","sources":{"KJV":{"text":"That we should be to the praise of his glory, who first trusted in Christ."}},"definableWords":[],"peopleInVerse":[]},"13":{"text":"In whom ye also trusted, after that ye heard the word of truth, the gospel of your salvation: in whom also after that ye believed, ye were sealed with that holy Spirit of promise,","ref":"Ephesians 1:13","synthesized":"In whom ye also trusted, after that ye heard the word of truth, the gospel of your salvation: in whom also after that ye believed, ye were sealed with that holy Spirit of promise,","sources":{"KJV":{"text":"In whom ye also trusted, after that ye heard the word of truth, the gospel of your salvation: in whom also after that ye believed, ye were sealed with that holy Spirit of promise,"}},"definableWords":[],"peopleInVerse":[]},"14":{"text":"Which is the earnest of our inheritance until the redemption of the purchased possession, unto the praise of his glory.","ref":"Ephesians 1:14","synthesized":"Which is the earnest of our inheritance until the redemption of the purchased possession, unto the praise of his glory.","sources":{"KJV":{"text":"Which is the earnest of our inheritance until the redemption of the purchased possession, unto the praise of his glory."}},"definableWords":[],"peopleInVerse":[]},"15":{"text":"Wherefore I also, after I heard of your faith in the Lord Jesus, and love unto all the saints,","ref":"Ephesians 1:15","synthesized":"Wherefore I also, after I heard of your faith in the Lord Jesus, and love unto all the saints,","sources":{"KJV":{"text":"Wherefore I also, after I heard of your faith in the Lord Jesus, and love unto all the saints,"}},"definableWords":[],"peopleInVerse":[]},"16":{"text":"Cease not to give thanks for you, making mention of you in my prayers;","ref":"Ephesians 1:16","synthesized":"Cease not to give thanks for you, making mention of you in my prayers;","sources":{"KJV":{"text":"Cease not to give thanks for you, making mention of you in my prayers;"}},"definableWords":[],"peopleInVerse":[]},"17":{"text":"That the God of our Lord Jesus Christ, the Father of glory, may give unto you the spirit of wisdom and revelation in the knowledge of him:","ref":"Ephesians 1:17","synthesized":"That the God of our Lord Jesus Christ, the Father of glory, may give unto you the spirit of wisdom and revelation in the knowledge of him:","sources":{"KJV":{"text":"That the God of our Lord Jesus Christ, the Father of glory, may give unto you the spirit of wisdom and revelation in the knowledge of him:"}},"definableWords":[],"peopleInVerse":[]},"18":{"text":"The eyes of your understanding being enlightened; that ye may know what is the hope of his calling, and what the riches of the glory of his inheritance in the saints,","ref":"Ephesians 1:18","synthesized":"The eyes of your understanding being enlightened; that ye may know what is the hope of his calling, and what the riches of the glory of his inheritance in the saints,","sources":{"KJV":{"text":"The eyes of your understanding being enlightened; that ye may know what is the hope of his calling, and what the riches of the glory of his inheritance in the saints,"}},"definableWords":[],"peopleInVerse":[]},"19":{"text":"And what is the exceeding greatness of his power to us-ward who believe, according to the working of his mighty power,","ref":"Ephesians 1:19","synthesized":"And what is the exceeding greatness of his power to us-ward who believe, according to the working of his mighty power,","sources":{"KJV":{"text":"And what is the exceeding greatness of his power to us-ward who believe, according to the working of his mighty power,"}},"definableWords":[],"peopleInVerse":[]},"20":{"text":"Which he wrought in Christ, when he raised him from the dead, and set him at his own right hand in the heavenly places,","ref":"Ephesians 1:20","synthesized":"Which he wrought in Christ, when he raised him from the dead, and set him at his own right hand in the heavenly places,","sources":{"KJV":{"text":"Which he wrought in Christ, when he raised him from the dead, and set him at his own right hand in the heavenly places,"}},"definableWords":[],"peopleInVerse":[]},"21":{"text":"Far above all principality, and power, and might, and dominion, and every name that is named, not only in this world, but also in that which is to come:","ref":"Ephesians 1:21","synthesized":"Far above all principality, and power, and might, and dominion, and every name that is named, not only in this world, but also in that which is to come:","sources":{"KJV":{"text":"Far above all principality, and power, and might, and dominion, and every name that is named, not only in this world, but also in that which is to come:"}},"definableWords":[],"peopleInVerse":[]},"22":{"text":"And hath put all things under his feet, and gave him to be the head over all things to the church,","ref":"Ephesians 1:22","synthesized":"And hath put all things under his feet, and gave him to be the head over all things to the church,","sources":{"KJV":{"text":"And hath put all things under his feet, and gave him to be the head over all things to the church,"}},"definableWords":[],"peopleInVerse":[]},"23":{"text":"Which is his body, the fulness of him that filleth all in all.","ref":"Ephesians 1:23","synthesized":"Which is his body, the fulness of him that filleth all in all.","sources":{"KJV":{"text":"Which is his body, the fulness of him that filleth all in all."}},"definableWords":[],"peopleInVerse":[]}}},"2":{"chapter":"2","title":"Ephesians 2","verses":{"1":{"text":"And you hath he quickened, who were dead in trespasses and sins;","ref":"Ephesians 2:1","synthesized":"And you hath he quickened, who were dead in trespasses and sins;","sources":{"KJV":{"text":"And you hath he quickened, who were dead in trespasses and sins;"}},"definableWords":[],"peopleInVerse":[]},"2":{"text":"Wherein in time past ye walked according to the course of this world, according to the prince of the power of the air, the spirit that now worketh in the children of disobedience:","ref":"Ephesians 2:2","synthesized":"Wherein in time past ye walked according to the course of this world, according to the prince of the power of the air, the spirit that now worketh in the children of disobedience:","sources":{"KJV":{"text":"Wherein in time past ye walked according to the course of this world, according to the prince of the power of the air, the spirit that now worketh in the children of disobedience:"}},"definableWords":[],"peopleInVerse":[]},"3":{"text":"Among whom also we all had our conversation in times past in the lusts of our flesh, fulfilling the desires of the flesh and of the mind; and were by nature the children of wrath, even as others.","ref":"Ephesians 2:3","synthesized":"Among whom also we all had our conversation in times past in the lusts of our flesh, fulfilling the desires of the flesh and of the mind; and were by nature the children of wrath, even as others.","sources":{"KJV":{"text":"Among whom also we all had our conversation in times past in the lusts of our flesh, fulfilling the desires of the flesh and of the mind; and were by nature the children of wrath, even as others."}},"definableWords":[],"peopleInVerse":[]},"4":{"text":"But God, who is rich in mercy, for his great love wherewith he loved us,","ref":"Ephesians 2:4","synthesized":"But God, who is rich in mercy, for his great love wherewith he loved us,","sources":{"KJV":{"text":"But God, who is rich in mercy, for his great love wherewith he loved us,"}},"definableWords":[],"peopleInVerse":[]},"5":{"text":"Even when we were dead in sins, hath quickened us together with Christ, (by grace ye are saved;)","ref":"Ephesians 2:5","synthesized":"Even when we were dead in sins, hath quickened us together with Christ, (by grace ye are saved;)","sources":{"KJV":{"text":"Even when we were dead in sins, hath quickened us together with Christ, (by grace ye are saved;)"}},"definableWords":[],"peopleInVerse":[]},"6":{"text":"And hath raised us up together, and made us sit together in heavenly places in Christ Jesus:","ref":"Ephesians 2:6","synthesized":"And hath raised us up together, and made us sit together in heavenly places in Christ Jesus:","sources":{"KJV":{"text":"And hath raised us up together, and made us sit together in heavenly places in Christ Jesus:"}},"definableWords":[],"peopleInVerse":[]},"7":{"text":"That in the ages to come he might shew the exceeding riches of his grace in his kindness toward us through Christ Jesus.","ref":"Ephesians 2:7","synthesized":"That in the ages to come he might shew the exceeding riches of his grace in his kindness toward us through Christ Jesus.","sources":{"KJV":{"text":"That in the ages to come he might shew the exceeding riches of his grace in his kindness toward us through Christ Jesus."}},"definableWords":[],"peopleInVerse":[]},"8":{"text":"For by grace are ye saved through faith; and that not of yourselves: it is the gift of God:","ref":"Ephesians 2:8","synthesized":"For by grace are ye saved through faith; and that not of yourselves: it is the gift of God:","sources":{"KJV":{"text":"For by grace are ye saved through faith; and that not of yourselves: it is the gift of God:"}},"definableWords":[],"peopleInVerse":[]},"9":{"text":"Not of works, lest any man should boast.","ref":"Ephesians 2:9","synthesized":"Not of works, lest any man should boast.","sources":{"KJV":{"text":"Not of works, lest any man should boast."}},"definableWords":[],"peopleInVerse":[]},"10":{"text":"For we are his workmanship, created in Christ Jesus unto good works, which God hath before ordained that we should walk in them.","ref":"Ephesians 2:10","synthesized":"For we are his workmanship, created in Christ Jesus unto good works, which God hath before ordained that we should walk in them.","sources":{"KJV":{"text":"For we are his workmanship, created in Christ Jesus unto good works, which God hath before ordained that we should walk in them."}},"definableWords":[],"peopleInVerse":[]},"11":{"text":"Wherefore remember, that ye being in time past Gentiles in the flesh, who are called Uncircumcision by that which is called the Circumcision in the flesh made by hands;","ref":"Ephesians 2:11","synthesized":"Wherefore remember, that ye being in time past Gentiles in the flesh, who are called Uncircumcision by that which is called the Circumcision in the flesh made by hands;","sources":{"KJV":{"text":"Wherefore remember, that ye being in time past Gentiles in the flesh, who are called Uncircumcision by that which is called the Circumcision in the flesh made by hands;"}},"definableWords":[],"peopleInVerse":[]},"12":{"text":"That at that time ye were without Christ, being aliens from the commonwealth of Israel, and strangers from the covenants of promise, having no hope, and without God in the world:","ref":"Ephesians 2:12","synthesized":"That at that time ye were without Christ, being aliens from the commonwealth of Israel, and strangers from the covenants of promise, having no hope, and without God in the world:","sources":{"KJV":{"text":"That at that time ye were without Christ, being aliens from the commonwealth of Israel, and strangers from the covenants of promise, having no hope, and without God in the world:"}},"definableWords":[],"peopleInVerse":[]},"13":{"text":"But now in Christ Jesus ye who sometimes were far off are made nigh by the blood of Christ.","ref":"Ephesians 2:13","synthesized":"But now in Christ Jesus ye who sometimes were far off are made nigh by the blood of Christ.","sources":{"KJV":{"text":"But now in Christ Jesus ye who sometimes were far off are made nigh by the blood of Christ."}},"definableWords":[],"peopleInVerse":[]},"14":{"text":"For he is our peace, who hath made both one, and hath broken down the middle wall of partition between us;","ref":"Ephesians 2:14","synthesized":"For he is our peace, who hath made both one, and hath broken down the middle wall of partition between us;","sources":{"KJV":{"text":"For he is our peace, who hath made both one, and hath broken down the middle wall of partition between us;"}},"definableWords":[],"peopleInVerse":[]},"15":{"text":"Having abolished in his flesh the enmity, even the law of commandments contained in ordinances; for to make in himself of twain one new man, so making peace;","ref":"Ephesians 2:15","synthesized":"Having abolished in his flesh the enmity, even the law of commandments contained in ordinances; for to make in himself of twain one new man, so making peace;","sources":{"KJV":{"text":"Having abolished in his flesh the enmity, even the law of commandments contained in ordinances; for to make in himself of twain one new man, so making peace;"}},"definableWords":[],"peopleInVerse":[]},"16":{"text":"And that he might reconcile both unto God in one body by the cross, having slain the enmity thereby:","ref":"Ephesians 2:16","synthesized":"And that he might reconcile both unto God in one body by the cross, having slain the enmity thereby:","sources":{"KJV":{"text":"And that he might reconcile both unto God in one body by the cross, having slain the enmity thereby:"}},"definableWords":[],"peopleInVerse":[]},"17":{"text":"And came and preached peace to you which were afar off, and to them that were nigh.","ref":"Ephesians 2:17","synthesized":"And came and preached peace to you which were afar off, and to them that were nigh.","sources":{"KJV":{"text":"And came and preached peace to you which were afar off, and to them that were nigh."}},"definableWords":[],"peopleInVerse":[]},"18":{"text":"For through him we both have access by one Spirit unto the Father.","ref":"Ephesians 2:18","synthesized":"For through him we both have access by one Spirit unto the Father.","sources":{"KJV":{"text":"For through him we both have access by one Spirit unto the Father."}},"definableWords":[],"peopleInVerse":[]},"19":{"text":"Now therefore ye are no more strangers and foreigners, but fellowcitizens with the saints, and of the household of God;","ref":"Ephesians 2:19","synthesized":"Now therefore ye are no more strangers and foreigners, but fellowcitizens with the saints, and of the household of God;","sources":{"KJV":{"text":"Now therefore ye are no more strangers and foreigners, but fellowcitizens with the saints, and of the household of God;"}},"definableWords":[],"peopleInVerse":[]},"20":{"text":"And are built upon the foundation of the apostles and prophets, Jesus Christ himself being the chief corner stone;","ref":"Ephesians 2:20","synthesized":"And are built upon the foundation of the apostles and prophets, Jesus Christ himself being the chief corner stone;","sources":{"KJV":{"text":"And are built upon the foundation of the apostles and prophets, Jesus Christ himself being the chief corner stone;"}},"definableWords":[],"peopleInVerse":[]},"21":{"text":"In whom all the building fitly framed together groweth unto an holy temple in the Lord:","ref":"Ephesians 2:21","synthesized":"In whom all the building fitly framed together groweth unto an holy temple in the Lord:","sources":{"KJV":{"text":"In whom all the building fitly framed together groweth unto an holy temple in the Lord:"}},"definableWords":[],"peopleInVerse":[]},"22":{"text":"In whom ye also are builded together for an habitation of God through the Spirit.","ref":"Ephesians 2:22","synthesized":"In whom ye also are builded together for an habitation of God through the Spirit.","sources":{"KJV":{"text":"In whom ye also are builded together for an habitation of God through the Spirit."}},"definableWords":[],"peopleInVerse":[]}}},"3":{"chapter":"3","title":"Ephesians 3","verses":{"1":{"text":"For this cause I Paul, the prisoner of Jesus Christ for you Gentiles,","ref":"Ephesians 3:1","synthesized":"For this cause I Paul, the prisoner of Jesus Christ for you Gentiles,","sources":{"KJV":{"text":"For this cause I Paul, the prisoner of Jesus Christ for you Gentiles,"}},"definableWords":[],"peopleInVerse":[]},"2":{"text":"If ye have heard of the dispensation of the grace of God which is given me to you-ward:","ref":"Ephesians 3:2","synthesized":"If ye have heard of the dispensation of the grace of God which is given me to you-ward:","sources":{"KJV":{"text":"If ye have heard of the dispensation of the grace of God which is given me to you-ward:"}},"definableWords":[],"peopleInVerse":[]},"3":{"text":"How that by revelation he made known unto me the mystery; (as I wrote afore in few words,","ref":"Ephesians 3:3","synthesized":"How that by revelation he made known unto me the mystery; (as I wrote afore in few words,","sources":{"KJV":{"text":"How that by revelation he made known unto me the mystery; (as I wrote afore in few words,"}},"definableWords":[],"peopleInVerse":[]},"4":{"text":"Whereby, when ye read, ye may understand my knowledge in the mystery of Christ)","ref":"Ephesians 3:4","synthesized":"Whereby, when ye read, ye may understand my knowledge in the mystery of Christ)","sources":{"KJV":{"text":"Whereby, when ye read, ye may understand my knowledge in the mystery of Christ)"}},"definableWords":[],"peopleInVerse":[]},"5":{"text":"Which in other ages was not made known unto the sons of men, as it is now revealed unto his holy apostles and prophets by the Spirit;","ref":"Ephesians 3:5","synthesized":"Which in other ages was not made known unto the sons of men, as it is now revealed unto his holy apostles and prophets by the Spirit;","sources":{"KJV":{"text":"Which in other ages was not made known unto the sons of men, as it is now revealed unto his holy apostles and prophets by the Spirit;"}},"definableWords":[],"peopleInVerse":[]},"6":{"text":"That the Gentiles should be fellowheirs, and of the same body, and partakers of his promise in Christ by the gospel:","ref":"Ephesians 3:6","synthesized":"That the Gentiles should be fellowheirs, and of the same body, and partakers of his promise in Christ by the gospel:","sources":{"KJV":{"text":"That the Gentiles should be fellowheirs, and of the same body, and partakers of his promise in Christ by the gospel:"}},"definableWords":[],"peopleInVerse":[]},"7":{"text":"Whereof I was made a minister, according to the gift of the grace of God given unto me by the effectual working of his power.","ref":"Ephesians 3:7","synthesized":"Whereof I was made a minister, according to the gift of the grace of God given unto me by the effectual working of his power.","sources":{"KJV":{"text":"Whereof I was made a minister, according to the gift of the grace of God given unto me by the effectual working of his power."}},"definableWords":[],"peopleInVerse":[]},"8":{"text":"Unto me, who am less than the least of all saints, is this grace given, that I should preach among the Gentiles the unsearchable riches of Christ;","ref":"Ephesians 3:8","synthesized":"Unto me, who am less than the least of all saints, is this grace given, that I should preach among the Gentiles the unsearchable riches of Christ;","sources":{"KJV":{"text":"Unto me, who am less than the least of all saints, is this grace given, that I should preach among the Gentiles the unsearchable riches of Christ;"}},"definableWords":[],"peopleInVerse":[]},"9":{"text":"And to make all men see what is the fellowship of the mystery, which from the beginning of the world hath been hid in God, who created all things by Jesus Christ:","ref":"Ephesians 3:9","synthesized":"And to make all men see what is the fellowship of the mystery, which from the beginning of the world hath been hid in God, who created all things by Jesus Christ:","sources":{"KJV":{"text":"And to make all men see what is the fellowship of the mystery, which from the beginning of the world hath been hid in God, who created all things by Jesus Christ:"}},"definableWords":[],"peopleInVerse":[]},"10":{"text":"To the intent that now unto the principalities and powers in heavenly places might be known by the church the manifold wisdom of God,","ref":"Ephesians 3:10","synthesized":"To the intent that now unto the principalities and powers in heavenly places might be known by the church the manifold wisdom of God,","sources":{"KJV":{"text":"To the intent that now unto the principalities and powers in heavenly places might be known by the church the manifold wisdom of God,"}},"definableWords":[],"peopleInVerse":[]},"11":{"text":"According to the eternal purpose which he purposed in Christ Jesus our Lord:","ref":"Ephesians 3:11","synthesized":"According to the eternal purpose which he purposed in Christ Jesus our Lord:","sources":{"KJV":{"text":"According to the eternal purpose which he purposed in Christ Jesus our Lord:"}},"definableWords":[],"peopleInVerse":[]},"12":{"text":"In whom we have boldness and access with confidence by the faith of him.","ref":"Ephesians 3:12","synthesized":"In whom we have boldness and access with confidence by the faith of him.","sources":{"KJV":{"text":"In whom we have boldness and access with confidence by the faith of him."}},"definableWords":[],"peopleInVerse":[]},"13":{"text":"Wherefore I desire that ye faint not at my tribulations for you, which is your glory.","ref":"Ephesians 3:13","synthesized":"Wherefore I desire that ye faint not at my tribulations for you, which is your glory.","sources":{"KJV":{"text":"Wherefore I desire that ye faint not at my tribulations for you, which is your glory."}},"definableWords":[],"peopleInVerse":[]},"14":{"text":"For this cause I bow my knees unto the Father of our Lord Jesus Christ,","ref":"Ephesians 3:14","synthesized":"For this cause I bow my knees unto the Father of our Lord Jesus Christ,","sources":{"KJV":{"text":"For this cause I bow my knees unto the Father of our Lord Jesus Christ,"}},"definableWords":[],"peopleInVerse":[]},"15":{"text":"Of whom the whole family in heaven and earth is named,","ref":"Ephesians 3:15","synthesized":"Of whom the whole family in heaven and earth is named,","sources":{"KJV":{"text":"Of whom the whole family in heaven and earth is named,"}},"definableWords":[],"peopleInVerse":[]},"16":{"text":"That he would grant you, according to the riches of his glory, to be strengthened with might by his Spirit in the inner man;","ref":"Ephesians 3:16","synthesized":"That he would grant you, according to the riches of his glory, to be strengthened with might by his Spirit in the inner man;","sources":{"KJV":{"text":"That he would grant you, according to the riches of his glory, to be strengthened with might by his Spirit in the inner man;"}},"definableWords":[],"peopleInVerse":[]},"17":{"text":"That Christ may dwell in your hearts by faith; that ye, being rooted and grounded in love,","ref":"Ephesians 3:17","synthesized":"That Christ may dwell in your hearts by faith; that ye, being rooted and grounded in love,","sources":{"KJV":{"text":"That Christ may dwell in your hearts by faith; that ye, being rooted and grounded in love,"}},"definableWords":[],"peopleInVerse":[]},"18":{"text":"May be able to comprehend with all saints what is the breadth, and length, and depth, and height;","ref":"Ephesians 3:18","synthesized":"May be able to comprehend with all saints what is the breadth, and length, and depth, and height;","sources":{"KJV":{"text":"May be able to comprehend with all saints what is the breadth, and length, and depth, and height;"}},"definableWords":[],"peopleInVerse":[]},"19":{"text":"And to know the love of Christ, which passeth knowledge, that ye might be filled with all the fulness of God.","ref":"Ephesians 3:19","synthesized":"And to know the love of Christ, which passeth knowledge, that ye might be filled with all the fulness of God.","sources":{"KJV":{"text":"And to know the love of Christ, which passeth knowledge, that ye might be filled with all the fulness of God."}},"definableWords":[],"peopleInVerse":[]},"20":{"text":"Now unto him that is able to do exceeding abundantly above all that we ask or think, according to the power that worketh in us,","ref":"Ephesians 3:20","synthesized":"Now unto him that is able to do exceeding abundantly above all that we ask or think, according to the power that worketh in us,","sources":{"KJV":{"text":"Now unto him that is able to do exceeding abundantly above all that we ask or think, according to the power that worketh in us,"}},"definableWords":[],"peopleInVerse":[]},"21":{"text":"Unto him be glory in the church by Christ Jesus throughout all ages, world without end. Amen.","ref":"Ephesians 3:21","synthesized":"Unto him be glory in the church by Christ Jesus throughout all ages, world without end. Amen.","sources":{"KJV":{"text":"Unto him be glory in the church by Christ Jesus throughout all ages, world without end. Amen."}},"definableWords":[],"peopleInVerse":[]}}},"4":{"chapter":"4","title":"Ephesians 4","verses":{"1":{"text":"I therefore, the prisoner of the Lord, beseech you that ye walk worthy of the vocation wherewith ye are called,","ref":"Ephesians 4:1","synthesized":"I therefore, the prisoner of the Lord, beseech you that ye walk worthy of the vocation wherewith ye are called,","sources":{"KJV":{"text":"I therefore, the prisoner of the Lord, beseech you that ye walk worthy of the vocation wherewith ye are called,"}},"definableWords":[],"peopleInVerse":[]},"2":{"text":"With all lowliness and meekness, with longsuffering, forbearing one another in love;","ref":"Ephesians 4:2","synthesized":"With all lowliness and meekness, with longsuffering, forbearing one another in love;","sources":{"KJV":{"text":"With all lowliness and meekness, with longsuffering, forbearing one another in love;"}},"definableWords":[],"peopleInVerse":[]},"3":{"text":"Endeavouring to keep the unity of the Spirit in the bond of peace.","ref":"Ephesians 4:3","synthesized":"Endeavouring to keep the unity of the Spirit in the bond of peace.","sources":{"KJV":{"text":"Endeavouring to keep the unity of the Spirit in the bond of peace."}},"definableWords":[],"peopleInVerse":[]},"4":{"text":"There is one body, and one Spirit, even as ye are called in one hope of your calling;","ref":"Ephesians 4:4","synthesized":"There is one body, and one Spirit, even as ye are called in one hope of your calling;","sources":{"KJV":{"text":"There is one body, and one Spirit, even as ye are called in one hope of your calling;"}},"definableWords":[],"peopleInVerse":[]},"5":{"text":"One Lord, one faith, one baptism,","ref":"Ephesians 4:5","synthesized":"One Lord, one faith, one baptism,","sources":{"KJV":{"text":"One Lord, one faith, one baptism,"}},"definableWords":[],"peopleInVerse":[]},"6":{"text":"One God and Father of all, who is above all, and through all, and in you all.","ref":"Ephesians 4:6","synthesized":"One God and Father of all, who is above all, and through all, and in you all.","sources":{"KJV":{"text":"One God and Father of all, who is above all, and through all, and in you all."}},"definableWords":[],"peopleInVerse":[]},"7":{"text":"But unto every one of us is given grace according to the measure of the gift of Christ.","ref":"Ephesians 4:7","synthesized":"But unto every one of us is given grace according to the measure of the gift of Christ.","sources":{"KJV":{"text":"But unto every one of us is given grace according to the measure of the gift of Christ."}},"definableWords":[],"peopleInVerse":[]},"8":{"text":"Wherefore he saith, When he ascended up on high, he led captivity captive, and gave gifts unto men.","ref":"Ephesians 4:8","synthesized":"Wherefore he saith, When he ascended up on high, he led captivity captive, and gave gifts unto men.","sources":{"KJV":{"text":"Wherefore he saith, When he ascended up on high, he led captivity captive, and gave gifts unto men."}},"definableWords":[],"peopleInVerse":[]},"9":{"text":"(Now that he ascended, what is it but that he also descended first into the lower parts of the earth?","ref":"Ephesians 4:9","synthesized":"(Now that he ascended, what is it but that he also descended first into the lower parts of the earth?","sources":{"KJV":{"text":"(Now that he ascended, what is it but that he also descended first into the lower parts of the earth?"}},"definableWords":[],"peopleInVerse":[]},"10":{"text":"He that descended is the same also that ascended up far above all heavens, that he might fill all things.)","ref":"Ephesians 4:10","synthesized":"He that descended is the same also that ascended up far above all heavens, that he might fill all things.)","sources":{"KJV":{"text":"He that descended is the same also that ascended up far above all heavens, that he might fill all things.)"}},"definableWords":[],"peopleInVerse":[]},"11":{"text":"And he gave some, apostles; and some, prophets; and some, evangelists; and some, pastors and teachers;","ref":"Ephesians 4:11","synthesized":"And he gave some, apostles; and some, prophets; and some, evangelists; and some, pastors and teachers;","sources":{"KJV":{"text":"And he gave some, apostles; and some, prophets; and some, evangelists; and some, pastors and teachers;"}},"definableWords":[],"peopleInVerse":[]},"12":{"text":"For the perfecting of the saints, for the work of the ministry, for the edifying of the body of Christ:","ref":"Ephesians 4:12","synthesized":"For the perfecting of the saints, for the work of the ministry, for the edifying of the body of Christ:","sources":{"KJV":{"text":"For the perfecting of the saints, for the work of the ministry, for the edifying of the body of Christ:"}},"definableWords":[],"peopleInVerse":[]},"13":{"text":"Till we all come in the unity of the faith, and of the knowledge of the Son of God, unto a perfect man, unto the measure of the stature of the fulness of Christ:","ref":"Ephesians 4:13","synthesized":"Till we all come in the unity of the faith, and of the knowledge of the Son of God, unto a perfect man, unto the measure of the stature of the fulness of Christ:","sources":{"KJV":{"text":"Till we all come in the unity of the faith, and of the knowledge of the Son of God, unto a perfect man, unto the measure of the stature of the fulness of Christ:"}},"definableWords":[],"peopleInVerse":[]},"14":{"text":"That we henceforth be no more children, tossed to and fro, and carried about with every wind of doctrine, by the sleight of men, and cunning craftiness, whereby they lie in wait to deceive;","ref":"Ephesians 4:14","synthesized":"That we henceforth be no more children, tossed to and fro, and carried about with every wind of doctrine, by the sleight of men, and cunning craftiness, whereby they lie in wait to deceive;","sources":{"KJV":{"text":"That we henceforth be no more children, tossed to and fro, and carried about with every wind of doctrine, by the sleight of men, and cunning craftiness, whereby they lie in wait to deceive;"}},"definableWords":[],"peopleInVerse":[]},"15":{"text":"But speaking the truth in love, may grow up into him in all things, which is the head, even Christ:","ref":"Ephesians 4:15","synthesized":"But speaking the truth in love, may grow up into him in all things, which is the head, even Christ:","sources":{"KJV":{"text":"But speaking the truth in love, may grow up into him in all things, which is the head, even Christ:"}},"definableWords":[],"peopleInVerse":[]},"16":{"text":"From whom the whole body fitly joined together and compacted by that which every joint supplieth, according to the effectual working in the measure of every part, maketh increase of the body unto the edifying of itself in love.","ref":"Ephesians 4:16","synthesized":"From whom the whole body fitly joined together and compacted by that which every joint supplieth, according to the effectual working in the measure of every part, maketh increase of the body unto the edifying of itself in love.","sources":{"KJV":{"text":"From whom the whole body fitly joined together and compacted by that which every joint supplieth, according to the effectual working in the measure of every part, maketh increase of the body unto the edifying of itself in love."}},"definableWords":[],"peopleInVerse":[]},"17":{"text":"This I say therefore, and testify in the Lord, that ye henceforth walk not as other Gentiles walk, in the vanity of their mind,","ref":"Ephesians 4:17","synthesized":"This I say therefore, and testify in the Lord, that ye henceforth walk not as other Gentiles walk, in the vanity of their mind,","sources":{"KJV":{"text":"This I say therefore, and testify in the Lord, that ye henceforth walk not as other Gentiles walk, in the vanity of their mind,"}},"definableWords":[],"peopleInVerse":[]},"18":{"text":"Having the understanding darkened, being alienated from the life of God through the ignorance that is in them, because of the blindness of their heart:","ref":"Ephesians 4:18","synthesized":"Having the understanding darkened, being alienated from the life of God through the ignorance that is in them, because of the blindness of their heart:","sources":{"KJV":{"text":"Having the understanding darkened, being alienated from the life of God through the ignorance that is in them, because of the blindness of their heart:"}},"definableWords":[],"peopleInVerse":[]},"19":{"text":"Who being past feeling have given themselves over unto lasciviousness, to work all uncleanness with greediness.","ref":"Ephesians 4:19","synthesized":"Who being past feeling have given themselves over unto lasciviousness, to work all uncleanness with greediness.","sources":{"KJV":{"text":"Who being past feeling have given themselves over unto lasciviousness, to work all uncleanness with greediness."}},"definableWords":[],"peopleInVerse":[]},"20":{"text":"But ye have not so learned Christ;","ref":"Ephesians 4:20","synthesized":"But ye have not so learned Christ;","sources":{"KJV":{"text":"But ye have not so learned Christ;"}},"definableWords":[],"peopleInVerse":[]},"21":{"text":"If so be that ye have heard him, and have been taught by him, as the truth is in Jesus:","ref":"Ephesians 4:21","synthesized":"If so be that ye have heard him, and have been taught by him, as the truth is in Jesus:","sources":{"KJV":{"text":"If so be that ye have heard him, and have been taught by him, as the truth is in Jesus:"}},"definableWords":[],"peopleInVerse":[]},"22":{"text":"That ye put off concerning the former conversation the old man, which is corrupt according to the deceitful lusts;","ref":"Ephesians 4:22","synthesized":"That ye put off concerning the former conversation the old man, which is corrupt according to the deceitful lusts;","sources":{"KJV":{"text":"That ye put off concerning the former conversation the old man, which is corrupt according to the deceitful lusts;"}},"definableWords":[],"peopleInVerse":[]},"23":{"text":"And be renewed in the spirit of your mind;","ref":"Ephesians 4:23","synthesized":"And be renewed in the spirit of your mind;","sources":{"KJV":{"text":"And be renewed in the spirit of your mind;"}},"definableWords":[],"peopleInVerse":[]},"24":{"text":"And that ye put on the new man, which after God is created in righteousness and true holiness.","ref":"Ephesians 4:24","synthesized":"And that ye put on the new man, which after God is created in righteousness and true holiness.","sources":{"KJV":{"text":"And that ye put on the new man, which after God is created in righteousness and true holiness."}},"definableWords":[],"peopleInVerse":[]},"25":{"text":"Wherefore putting away lying, speak every man truth with his neighbour: for we are members one of another.","ref":"Ephesians 4:25","synthesized":"Wherefore putting away lying, speak every man truth with his neighbour: for we are members one of another.","sources":{"KJV":{"text":"Wherefore putting away lying, speak every man truth with his neighbour: for we are members one of another."}},"definableWords":[],"peopleInVerse":[]},"26":{"text":"Be ye angry, and sin not: let not the sun go down upon your wrath:","ref":"Ephesians 4:26","synthesized":"Be ye angry, and sin not: let not the sun go down upon your wrath:","sources":{"KJV":{"text":"Be ye angry, and sin not: let not the sun go down upon your wrath:"}},"definableWords":[],"peopleInVerse":[]},"27":{"text":"Neither give place to the devil.","ref":"Ephesians 4:27","synthesized":"Neither give place to the devil.","sources":{"KJV":{"text":"Neither give place to the devil."}},"definableWords":[],"peopleInVerse":[]},"28":{"text":"Let him that stole steal no more: but rather let him labour, working with his hands the thing which is good, that he may have to give to him that needeth.","ref":"Ephesians 4:28","synthesized":"Let him that stole steal no more: but rather let him labour, working with his hands the thing which is good, that he may have to give to him that needeth.","sources":{"KJV":{"text":"Let him that stole steal no more: but rather let him labour, working with his hands the thing which is good, that he may have to give to him that needeth."}},"definableWords":[],"peopleInVerse":[]},"29":{"text":"Let no corrupt communication proceed out of your mouth, but that which is good to the use of edifying, that it may minister grace unto the hearers.","ref":"Ephesians 4:29","synthesized":"Let no corrupt communication proceed out of your mouth, but that which is good to the use of edifying, that it may minister grace unto the hearers.","sources":{"KJV":{"text":"Let no corrupt communication proceed out of your mouth, but that which is good to the use of edifying, that it may minister grace unto the hearers."}},"definableWords":[],"peopleInVerse":[]},"30":{"text":"And grieve not the holy Spirit of God, whereby ye are sealed unto the day of redemption.","ref":"Ephesians 4:30","synthesized":"And grieve not the holy Spirit of God, whereby ye are sealed unto the day of redemption.","sources":{"KJV":{"text":"And grieve not the holy Spirit of God, whereby ye are sealed unto the day of redemption."}},"definableWords":[],"peopleInVerse":[]},"31":{"text":"Let all bitterness, and wrath, and anger, and clamour, and evil speaking, be put away from you, with all malice:","ref":"Ephesians 4:31","synthesized":"Let all bitterness, and wrath, and anger, and clamour, and evil speaking, be put away from you, with all malice:","sources":{"KJV":{"text":"Let all bitterness, and wrath, and anger, and clamour, and evil speaking, be put away from you, with all malice:"}},"definableWords":[],"peopleInVerse":[]},"32":{"text":"And be ye kind one to another, tenderhearted, forgiving one another, even as God for Christ’s sake hath forgiven you.","ref":"Ephesians 4:32","synthesized":"And be ye kind one to another, tenderhearted, forgiving one another, even as God for Christ’s sake hath forgiven you.","sources":{"KJV":{"text":"And be ye kind one to another, tenderhearted, forgiving one another, even as God for Christ’s sake hath forgiven you."}},"definableWords":[],"peopleInVerse":[]}}},"5":{"chapter":"5","title":"Ephesians 5","verses":{"1":{"text":"Be ye therefore followers of God, as dear children;","ref":"Ephesians 5:1","synthesized":"Be ye therefore followers of God, as dear children;","sources":{"KJV":{"text":"Be ye therefore followers of God, as dear children;"}},"definableWords":[],"peopleInVerse":[]},"2":{"text":"And walk in love, as Christ also hath loved us, and hath given himself for us an offering and a sacrifice to God for a sweetsmelling savour.","ref":"Ephesians 5:2","synthesized":"And walk in love, as Christ also hath loved us, and hath given himself for us an offering and a sacrifice to God for a sweetsmelling savour.","sources":{"KJV":{"text":"And walk in love, as Christ also hath loved us, and hath given himself for us an offering and a sacrifice to God for a sweetsmelling savour."}},"definableWords":[],"peopleInVerse":[]},"3":{"text":"But fornication, and all uncleanness, or covetousness, let it not be once named among you, as becometh saints;","ref":"Ephesians 5:3","synthesized":"But fornication, and all uncleanness, or covetousness, let it not be once named among you, as becometh saints;","sources":{"KJV":{"text":"But fornication, and all uncleanness, or covetousness, let it not be once named among you, as becometh saints;"}},"definableWords":[],"peopleInVerse":[]},"4":{"text":"Neither filthiness, nor foolish talking, nor jesting, which are not convenient: but rather giving of thanks.","ref":"Ephesians 5:4","synthesized":"Neither filthiness, nor foolish talking, nor jesting, which are not convenient: but rather giving of thanks.","sources":{"KJV":{"text":"Neither filthiness, nor foolish talking, nor jesting, which are not convenient: but rather giving of thanks."}},"definableWords":[],"peopleInVerse":[]},"5":{"text":"For this ye know, that no whoremonger, nor unclean person, nor covetous man, who is an idolater, hath any inheritance in the kingdom of Christ and of God.","ref":"Ephesians 5:5","synthesized":"For this ye know, that no whoremonger, nor unclean person, nor covetous man, who is an idolater, hath any inheritance in the kingdom of Christ and of God.","sources":{"KJV":{"text":"For this ye know, that no whoremonger, nor unclean person, nor covetous man, who is an idolater, hath any inheritance in the kingdom of Christ and of God."}},"definableWords":[],"peopleInVerse":[]},"6":{"text":"Let no man deceive you with vain words: for because of these things cometh the wrath of God upon the children of disobedience.","ref":"Ephesians 5:6","synthesized":"Let no man deceive you with vain words: for because of these things cometh the wrath of God upon the children of disobedience.","sources":{"KJV":{"text":"Let no man deceive you with vain words: for because of these things cometh the wrath of God upon the children of disobedience."}},"definableWords":[],"peopleInVerse":[]},"7":{"text":"Be not ye therefore partakers with them.","ref":"Ephesians 5:7","synthesized":"Be not ye therefore partakers with them.","sources":{"KJV":{"text":"Be not ye therefore partakers with them."}},"definableWords":[],"peopleInVerse":[]},"8":{"text":"For ye were sometimes darkness, but now are ye light in the Lord: walk as children of light:","ref":"Ephesians 5:8","synthesized":"For ye were sometimes darkness, but now are ye light in the Lord: walk as children of light:","sources":{"KJV":{"text":"For ye were sometimes darkness, but now are ye light in the Lord: walk as children of light:"}},"definableWords":[],"peopleInVerse":[]},"9":{"text":"(For the fruit of the Spirit is in all goodness and righteousness and truth;)","ref":"Ephesians 5:9","synthesized":"(For the fruit of the Spirit is in all goodness and righteousness and truth;)","sources":{"KJV":{"text":"(For the fruit of the Spirit is in all goodness and righteousness and truth;)"}},"definableWords":[],"peopleInVerse":[]},"10":{"text":"Proving what is acceptable unto the Lord.","ref":"Ephesians 5:10","synthesized":"Proving what is acceptable unto the Lord.","sources":{"KJV":{"text":"Proving what is acceptable unto the Lord."}},"definableWords":[],"peopleInVerse":[]},"11":{"text":"And have no fellowship with the unfruitful works of darkness, but rather reprove them.","ref":"Ephesians 5:11","synthesized":"And have no fellowship with the unfruitful works of darkness, but rather reprove them.","sources":{"KJV":{"text":"And have no fellowship with the unfruitful works of darkness, but rather reprove them."}},"definableWords":[],"peopleInVerse":[]},"12":{"text":"For it is a shame even to speak of those things which are done of them in secret.","ref":"Ephesians 5:12","synthesized":"For it is a shame even to speak of those things which are done of them in secret.","sources":{"KJV":{"text":"For it is a shame even to speak of those things which are done of them in secret."}},"definableWords":[],"peopleInVerse":[]},"13":{"text":"But all things that are reproved are made manifest by the light: for whatsoever doth make manifest is light.","ref":"Ephesians 5:13","synthesized":"But all things that are reproved are made manifest by the light: for whatsoever doth make manifest is light.","sources":{"KJV":{"text":"But all things that are reproved are made manifest by the light: for whatsoever doth make manifest is light."}},"definableWords":[],"peopleInVerse":[]},"14":{"text":"Wherefore he saith, Awake thou that sleepest, and arise from the dead, and Christ shall give thee light.","ref":"Ephesians 5:14","synthesized":"Wherefore he saith, Awake thou that sleepest, and arise from the dead, and Christ shall give thee light.","sources":{"KJV":{"text":"Wherefore he saith, Awake thou that sleepest, and arise from the dead, and Christ shall give thee light."}},"definableWords":[],"peopleInVerse":[]},"15":{"text":"See then that ye walk circumspectly, not as fools, but as wise,","ref":"Ephesians 5:15","synthesized":"See then that ye walk circumspectly, not as fools, but as wise,","sources":{"KJV":{"text":"See then that ye walk circumspectly, not as fools, but as wise,"}},"definableWords":[],"peopleInVerse":[]},"16":{"text":"Redeeming the time, because the days are evil.","ref":"Ephesians 5:16","synthesized":"Redeeming the time, because the days are evil.","sources":{"KJV":{"text":"Redeeming the time, because the days are evil."}},"definableWords":[],"peopleInVerse":[]},"17":{"text":"Wherefore be ye not unwise, but understanding what the will of the Lord is.","ref":"Ephesians 5:17","synthesized":"Wherefore be ye not unwise, but understanding what the will of the Lord is.","sources":{"KJV":{"text":"Wherefore be ye not unwise, but understanding what the will of the Lord is."}},"definableWords":[],"peopleInVerse":[]},"18":{"text":"And be not drunk with wine, wherein is excess; but be filled with the Spirit;","ref":"Ephesians 5:18","synthesized":"And be not drunk with wine, wherein is excess; but be filled with the Spirit;","sources":{"KJV":{"text":"And be not drunk with wine, wherein is excess; but be filled with the Spirit;"}},"definableWords":[],"peopleInVerse":[]},"19":{"text":"Speaking to yourselves in psalms and hymns and spiritual songs, singing and making melody in your heart to the Lord;","ref":"Ephesians 5:19","synthesized":"Speaking to yourselves in psalms and hymns and spiritual songs, singing and making melody in your heart to the Lord;","sources":{"KJV":{"text":"Speaking to yourselves in psalms and hymns and spiritual songs, singing and making melody in your heart to the Lord;"}},"definableWords":[],"peopleInVerse":[]},"20":{"text":"Giving thanks always for all things unto God and the Father in the name of our Lord Jesus Christ;","ref":"Ephesians 5:20","synthesized":"Giving thanks always for all things unto God and the Father in the name of our Lord Jesus Christ;","sources":{"KJV":{"text":"Giving thanks always for all things unto God and the Father in the name of our Lord Jesus Christ;"}},"definableWords":[],"peopleInVerse":[]},"21":{"text":"Submitting yourselves one to another in the fear of God.","ref":"Ephesians 5:21","synthesized":"Submitting yourselves one to another in the fear of God.","sources":{"KJV":{"text":"Submitting yourselves one to another in the fear of God."}},"definableWords":[],"peopleInVerse":[]},"22":{"text":"Wives, submit yourselves unto your own husbands, as unto the Lord.","ref":"Ephesians 5:22","synthesized":"Wives, submit yourselves unto your own husbands, as unto the Lord.","sources":{"KJV":{"text":"Wives, submit yourselves unto your own husbands, as unto the Lord."}},"definableWords":[],"peopleInVerse":[]},"23":{"text":"For the husband is the head of the wife, even as Christ is the head of the church: and he is the saviour of the body.","ref":"Ephesians 5:23","synthesized":"For the husband is the head of the wife, even as Christ is the head of the church: and he is the saviour of the body.","sources":{"KJV":{"text":"For the husband is the head of the wife, even as Christ is the head of the church: and he is the saviour of the body."}},"definableWords":[],"peopleInVerse":[]},"24":{"text":"Therefore as the church is subject unto Christ, so let the wives be to their own husbands in every thing.","ref":"Ephesians 5:24","synthesized":"Therefore as the church is subject unto Christ, so let the wives be to their own husbands in every thing.","sources":{"KJV":{"text":"Therefore as the church is subject unto Christ, so let the wives be to their own husbands in every thing."}},"definableWords":[],"peopleInVerse":[]},"25":{"text":"Husbands, love your wives, even as Christ also loved the church, and gave himself for it;","ref":"Ephesians 5:25","synthesized":"Husbands, love your wives, even as Christ also loved the church, and gave himself for it;","sources":{"KJV":{"text":"Husbands, love your wives, even as Christ also loved the church, and gave himself for it;"}},"definableWords":[],"peopleInVerse":[]},"26":{"text":"That he might sanctify and cleanse it with the washing of water by the word,","ref":"Ephesians 5:26","synthesized":"That he might sanctify and cleanse it with the washing of water by the word,","sources":{"KJV":{"text":"That he might sanctify and cleanse it with the washing of water by the word,"}},"definableWords":[],"peopleInVerse":[]},"27":{"text":"That he might present it to himself a glorious church, not having spot, or wrinkle, or any such thing; but that it should be holy and without blemish.","ref":"Ephesians 5:27","synthesized":"That he might present it to himself a glorious church, not having spot, or wrinkle, or any such thing; but that it should be holy and without blemish.","sources":{"KJV":{"text":"That he might present it to himself a glorious church, not having spot, or wrinkle, or any such thing; but that it should be holy and without blemish."}},"definableWords":[],"peopleInVerse":[]},"28":{"text":"So ought men to love their wives as their own bodies. He that loveth his wife loveth himself.","ref":"Ephesians 5:28","synthesized":"So ought men to love their wives as their own bodies. He that loveth his wife loveth himself.","sources":{"KJV":{"text":"So ought men to love their wives as their own bodies. He that loveth his wife loveth himself."}},"definableWords":[],"peopleInVerse":[]},"29":{"text":"For no man ever yet hated his own flesh; but nourisheth and cherisheth it, even as the Lord the church:","ref":"Ephesians 5:29","synthesized":"For no man ever yet hated his own flesh; but nourisheth and cherisheth it, even as the Lord the church:","sources":{"KJV":{"text":"For no man ever yet hated his own flesh; but nourisheth and cherisheth it, even as the Lord the church:"}},"definableWords":[],"peopleInVerse":[]},"30":{"text":"For we are members of his body, of his flesh, and of his bones.","ref":"Ephesians 5:30","synthesized":"For we are members of his body, of his flesh, and of his bones.","sources":{"KJV":{"text":"For we are members of his body, of his flesh, and of his bones."}},"definableWords":[],"peopleInVerse":[]},"31":{"text":"For this cause shall a man leave his father and mother, and shall be joined unto his wife, and they two shall be one flesh.","ref":"Ephesians 5:31","synthesized":"For this cause shall a man leave his father and mother, and shall be joined unto his wife, and they two shall be one flesh.","sources":{"KJV":{"text":"For this cause shall a man leave his father and mother, and shall be joined unto his wife, and they two shall be one flesh."}},"definableWords":[],"peopleInVerse":[]},"32":{"text":"This is a great mystery: but I speak concerning Christ and the church.","ref":"Ephesians 5:32","synthesized":"This is a great mystery: but I speak concerning Christ and the church.","sources":{"KJV":{"text":"This is a great mystery: but I speak concerning Christ and the church."}},"definableWords":[],"peopleInVerse":[]},"33":{"text":"Nevertheless let every one of you in particular so love his wife even as himself; and the wife see that she reverence her husband.","ref":"Ephesians 5:33","synthesized":"Nevertheless let every one of you in particular so love his wife even as himself; and the wife see that she reverence her husband.","sources":{"KJV":{"text":"Nevertheless let every one of you in particular so love his wife even as himself; and the wife see that she reverence her husband."}},"definableWords":[],"peopleInVerse":[]}}},"6":{"chapter":"6","title":"Ephesians 6","verses":{"1":{"text":"Children, obey your parents in the Lord: for this is right.","ref":"Ephesians 6:1","synthesized":"Children, obey your parents in the Lord: for this is right.","sources":{"KJV":{"text":"Children, obey your parents in the Lord: for this is right."}},"definableWords":[],"peopleInVerse":[]},"2":{"text":"Honour thy father and mother; which is the first commandment with promise;","ref":"Ephesians 6:2","synthesized":"Honour thy father and mother; which is the first commandment with promise;","sources":{"KJV":{"text":"Honour thy father and mother; which is the first commandment with promise;"}},"definableWords":[],"peopleInVerse":[]},"3":{"text":"That it may be well with thee, and thou mayest live long on the earth.","ref":"Ephesians 6:3","synthesized":"That it may be well with thee, and thou mayest live long on the earth.","sources":{"KJV":{"text":"That it may be well with thee, and thou mayest live long on the earth."}},"definableWords":[],"peopleInVerse":[]},"4":{"text":"And, ye fathers, provoke not your children to wrath: but bring them up in the nurture and admonition of the Lord.","ref":"Ephesians 6:4","synthesized":"And, ye fathers, provoke not your children to wrath: but bring them up in the nurture and admonition of the Lord.","sources":{"KJV":{"text":"And, ye fathers, provoke not your children to wrath: but bring them up in the nurture and admonition of the Lord."}},"definableWords":[],"peopleInVerse":[]},"5":{"text":"Servants, be obedient to them that are your masters according to the flesh, with fear and trembling, in singleness of your heart, as unto Christ;","ref":"Ephesians 6:5","synthesized":"Servants, be obedient to them that are your masters according to the flesh, with fear and trembling, in singleness of your heart, as unto Christ;","sources":{"KJV":{"text":"Servants, be obedient to them that are your masters according to the flesh, with fear and trembling, in singleness of your heart, as unto Christ;"}},"definableWords":[],"peopleInVerse":[]},"6":{"text":"Not with eyeservice, as menpleasers; but as the servants of Christ, doing the will of God from the heart;","ref":"Ephesians 6:6","synthesized":"Not with eyeservice, as menpleasers; but as the servants of Christ, doing the will of God from the heart;","sources":{"KJV":{"text":"Not with eyeservice, as menpleasers; but as the servants of Christ, doing the will of God from the heart;"}},"definableWords":[],"peopleInVerse":[]},"7":{"text":"With good will doing service, as to the Lord, and not to men:","ref":"Ephesians 6:7","synthesized":"With good will doing service, as to the Lord, and not to men:","sources":{"KJV":{"text":"With good will doing service, as to the Lord, and not to men:"}},"definableWords":[],"peopleInVerse":[]},"8":{"text":"Knowing that whatsoever good thing any man doeth, the same shall he receive of the Lord, whether he be bond or free.","ref":"Ephesians 6:8","synthesized":"Knowing that whatsoever good thing any man doeth, the same shall he receive of the Lord, whether he be bond or free.","sources":{"KJV":{"text":"Knowing that whatsoever good thing any man doeth, the same shall he receive of the Lord, whether he be bond or free."}},"definableWords":[],"peopleInVerse":[]},"9":{"text":"And, ye masters, do the same things unto them, forbearing threatening: knowing that your Master also is in heaven; neither is there respect of persons with him.","ref":"Ephesians 6:9","synthesized":"And, ye masters, do the same things unto them, forbearing threatening: knowing that your Master also is in heaven; neither is there respect of persons with him.","sources":{"KJV":{"text":"And, ye masters, do the same things unto them, forbearing threatening: knowing that your Master also is in heaven; neither is there respect of persons with him."}},"definableWords":[],"peopleInVerse":[]},"10":{"text":"Finally, my brethren, be strong in the Lord, and in the power of his might.","ref":"Ephesians 6:10","synthesized":"Finally, my brethren, be strong in the Lord, and in the power of his might.","sources":{"KJV":{"text":"Finally, my brethren, be strong in the Lord, and in the power of his might."}},"definableWords":[],"peopleInVerse":[]},"11":{"text":"Put on the whole armour of God, that ye may be able to stand against the wiles of the devil.","ref":"Ephesians 6:11","synthesized":"Put on the whole armour of God, that ye may be able to stand against the wiles of the devil.","sources":{"KJV":{"text":"Put on the whole armour of God, that ye may be able to stand against the wiles of the devil."}},"definableWords":[],"peopleInVerse":[]},"12":{"text":"For we wrestle not against flesh and blood, but against principalities, against powers, against the rulers of the darkness of this world, against spiritual wickedness in high places.","ref":"Ephesians 6:12","synthesized":"For we wrestle not against flesh and blood, but against principalities, against powers, against the rulers of the darkness of this world, against spiritual wickedness in high places.","sources":{"KJV":{"text":"For we wrestle not against flesh and blood, but against principalities, against powers, against the rulers of the darkness of this world, against spiritual wickedness in high places."}},"definableWords":[],"peopleInVerse":[]},"13":{"text":"Wherefore take unto you the whole armour of God, that ye may be able to withstand in the evil day, and having done all, to stand.","ref":"Ephesians 6:13","synthesized":"Wherefore take unto you the whole armour of God, that ye may be able to withstand in the evil day, and having done all, to stand.","sources":{"KJV":{"text":"Wherefore take unto you the whole armour of God, that ye may be able to withstand in the evil day, and having done all, to stand."}},"definableWords":[],"peopleInVerse":[]},"14":{"text":"Stand therefore, having your loins girt about with truth, and having on the breastplate of righteousness;","ref":"Ephesians 6:14","synthesized":"Stand therefore, having your loins girt about with truth, and having on the breastplate of righteousness;","sources":{"KJV":{"text":"Stand therefore, having your loins girt about with truth, and having on the breastplate of righteousness;"}},"definableWords":[],"peopleInVerse":[]},"15":{"text":"And your feet shod with the preparation of the gospel of peace;","ref":"Ephesians 6:15","synthesized":"And your feet shod with the preparation of the gospel of peace;","sources":{"KJV":{"text":"And your feet shod with the preparation of the gospel of peace;"}},"definableWords":[],"peopleInVerse":[]},"16":{"text":"Above all, taking the shield of faith, wherewith ye shall be able to quench all the fiery darts of the wicked.","ref":"Ephesians 6:16","synthesized":"Above all, taking the shield of faith, wherewith ye shall be able to quench all the fiery darts of the wicked.","sources":{"KJV":{"text":"Above all, taking the shield of faith, wherewith ye shall be able to quench all the fiery darts of the wicked."}},"definableWords":[],"peopleInVerse":[]},"17":{"text":"And take the helmet of salvation, and the sword of the Spirit, which is the word of God:","ref":"Ephesians 6:17","synthesized":"And take the helmet of salvation, and the sword of the Spirit, which is the word of God:","sources":{"KJV":{"text":"And take the helmet of salvation, and the sword of the Spirit, which is the word of God:"}},"definableWords":[],"peopleInVerse":[]},"18":{"text":"Praying always with all prayer and supplication in the Spirit, and watching thereunto with all perseverance and supplication for all saints;","ref":"Ephesians 6:18","synthesized":"Praying always with all prayer and supplication in the Spirit, and watching thereunto with all perseverance and supplication for all saints;","sources":{"KJV":{"text":"Praying always with all prayer and supplication in the Spirit, and watching thereunto with all perseverance and supplication for all saints;"}},"definableWords":[],"peopleInVerse":[]},"19":{"text":"And for me, that utterance may be given unto me, that I may open my mouth boldly, to make known the mystery of the gospel,","ref":"Ephesians 6:19","synthesized":"And for me, that utterance may be given unto me, that I may open my mouth boldly, to make known the mystery of the gospel,","sources":{"KJV":{"text":"And for me, that utterance may be given unto me, that I may open my mouth boldly, to make known the mystery of the gospel,"}},"definableWords":[],"peopleInVerse":[]},"20":{"text":"For which I am an ambassador in bonds: that therein I may speak boldly, as I ought to speak.","ref":"Ephesians 6:20","synthesized":"For which I am an ambassador in bonds: that therein I may speak boldly, as I ought to speak.","sources":{"KJV":{"text":"For which I am an ambassador in bonds: that therein I may speak boldly, as I ought to speak."}},"definableWords":[],"peopleInVerse":[]},"21":{"text":"But that ye also may know my affairs, and how I do, Tychicus, a beloved brother and faithful minister in the Lord, shall make known to you all things:","ref":"Ephesians 6:21","synthesized":"But that ye also may know my affairs, and how I do, Tychicus, a beloved brother and faithful minister in the Lord, shall make known to you all things:","sources":{"KJV":{"text":"But that ye also may know my affairs, and how I do, Tychicus, a beloved brother and faithful minister in the Lord, shall make known to you all things:"}},"definableWords":[],"peopleInVerse":[]},"22":{"text":"Whom I have sent unto you for the same purpose, that ye might know our affairs, and that he might comfort your hearts.","ref":"Ephesians 6:22","synthesized":"Whom I have sent unto you for the same purpose, that ye might know our affairs, and that he might comfort your hearts.","sources":{"KJV":{"text":"Whom I have sent unto you for the same purpose, that ye might know our affairs, and that he might comfort your hearts."}},"definableWords":[],"peopleInVerse":[]},"23":{"text":"Peace be to the brethren, and love with faith, from God the Father and the Lord Jesus Christ.","ref":"Ephesians 6:23","synthesized":"Peace be to the brethren, and love with faith, from God the Father and the Lord Jesus Christ.","sources":{"KJV":{"text":"Peace be to the brethren, and love with faith, from God the Father and the Lord Jesus Christ."}},"definableWords":[],"peopleInVerse":[]},"24":{"text":"Grace be with all them that love our Lord Jesus Christ in sincerity. Amen.","ref":"Ephesians 6:24","synthesized":"Grace be with all them that love our Lord Jesus Christ in sincerity. Amen.","sources":{"KJV":{"text":"Grace be with all them that love our Lord Jesus Christ in sincerity. Amen."}},"definableWords":[],"peopleInVerse":[]}}}};